import { UmbTextStyles } from "@umbraco-cms/backoffice/style";
import type {
  UmbTableColumn,
  UmbTableConfig,
  UmbTableDeselectedEvent,
  UmbTableElement,
  UmbTableItem,
  UmbTableSelectedEvent,
} from "@umbraco-cms/backoffice/components";
import {
  css,
  html,
  customElement,
  state,
  LitElement,
  property,
  when,
} from "@umbraco-cms/backoffice/external/lit";
import { UmbElementMixin } from "@umbraco-cms/backoffice/element-api";
import {
  type EntrySearchResultSchema,
  type FieldData,
} from "@umbraco-forms/generated";
import { UmbModalRouteRegistrationController } from "@umbraco-cms/backoffice/router";
import { FORMS_ENTRY_DETAILS_MODAL } from "@umbraco-forms/modals";
import { GUID_EMPTY } from "@umbraco-forms/entities";
import { FORMS_FORM_WORKSPACE_CONTEXT } from "../../../../workspace/form-workspace.context-token.js";
import type { FormEntryCollectionModel } from "../../../types.js";
import { FormsPrevalueSourceDetailRepository } from "../../../../../prevaluesources/repository/index.js";
import type { FieldPrevalueDetail } from "../../../../types.js";
import { FORMS_FORM_ENTRY_COLLECTION_CONTEXT } from "../../form-entry-collection.context-token.js";
import type { FormsEntryCollectionContext } from "../../form-entry-collection.context.js";
import { EntryRenderHelper } from "../../../entry-render-helper.class.js";

const elementName = "form-entry-table-collection-view";

@customElement(elementName)
export class FormsFormEntryTableCollectionViewElement extends UmbElementMixin(
  LitElement
) {
  #workspaceContext?: typeof FORMS_FORM_WORKSPACE_CONTEXT.TYPE;
  #collectionContext?: FormsEntryCollectionContext;

  #entries: Array<FormEntryCollectionModel> = [];

  @property({ type: Array })
  get selectedEntryIds() {
    return this.#collectionContext?.selection.getSelection();
  }

  @state()
  private _loading: boolean = false;

  @state()
  private _tableConfig: UmbTableConfig = {
    allowSelection: true,
  };

  @state()
  private _tableColumns: Array<UmbTableColumn> = [];

  @state()
  private _tableItems: Array<UmbTableItem> = [];

  #schema: Array<EntrySearchResultSchema> = [];
  #fieldPrevalues: Array<FieldPrevalueDetail> = [];
  #entryModalRouter?: UmbModalRouteRegistrationController;

  async connectedCallback() {
    super.connectedCallback();

    this.consumeContext(FORMS_FORM_WORKSPACE_CONTEXT, (context) => {
      this.#workspaceContext = context;
      this.observe(this.#workspaceContext.data, async (form) => {
        if (!form) return;

        this.#fieldPrevalues = this.#workspaceContext!.getFieldsWithPrevalues();
        await this.#ensurePrevalues(form.id);

        this.consumeContext(FORMS_FORM_ENTRY_COLLECTION_CONTEXT, (context) => {
          this.#collectionContext = context;
          this.#observeCollectionContext();
        });
      });
    });
  }

  async #ensurePrevalues(formId: string) {
    // Prevalues defined directly on the field will already be populated in #fieldPrevalues. Those defined
    // using a prevalue source need to be loaded so we have them when displaying and editing the entries.
    for (let i = 0; i < this.#fieldPrevalues.length; i++) {
      const fieldPrevalues = this.#fieldPrevalues[i];
      if (fieldPrevalues.prevalueSourceId !== GUID_EMPTY) {
        const prevalueSourceRepository =
          new FormsPrevalueSourceDetailRepository(this);
        const { data } = await prevalueSourceRepository.requestPrevalues(
          fieldPrevalues.prevalueSourceId,
          formId,
          fieldPrevalues.id
        );
        if (data) {
          fieldPrevalues.prevalues = data.map((pv) => {
            return {
              value: pv.value,
              caption: pv.caption,
            };
          });
        }
      }
    }
  }

  #observeCollectionContext() {
    if (!this.#collectionContext) return;

    this.observe(this.#collectionContext.loading, (loading) => (this._loading = loading), '_observeLoading');

    this.observe(
      this.#collectionContext.items,
      (items) => {
        this.#createTableColumnsAndItems(items);

        if (items.length && !this.#entryModalRouter) {
          this.#registerModal();
        }
      },
      "formsFormEntriesCollectionItemsObserver"
    );
  }

  #registerModal() {
    this.#entryModalRouter = new UmbModalRouteRegistrationController(
      this,
      FORMS_ENTRY_DETAILS_MODAL
    )
      .addAdditionalPath(":unique")
      .onSetup(async (params) => {
        const entry = this.#entries.find((e) => e.unique == params.unique);
        if (!entry) throw new Error("Could not find entry");
        return {
          data: {
            schema: this.#schema,
            fieldPrevalues: this.#fieldPrevalues,
          },
          value: entry,
        };
      })
      .onSubmit((value) => {
        // Re-apply existing filter to trigger fetch
        if (value.updateCollection) {
          this.#collectionContext?.requestCollection();
        }
      });
  }

  #createTableColumnsAndItems(entries: Array<FormEntryCollectionModel>) {
    if (entries.length === 0) return;

    // The top item contains the schema information.
    const schema = entries[0].schema;
    if (!schema) throw new Error("Schema not provided.");

    // Save the schema and entries so we can pass the necessary subset of them to the modal for viewing and editing entries.
    this.#schema = schema;
    this.#entries = entries.slice(1);

    this.#createTableColumns();
    this.#createTableItems(schema);
  }

  #createTableColumns() {
    const tableColumns = this.#schema
      .filter((s) => s.showOnListingScreen)
      .map((s) => ({
        name: s.name,
        alias: s.id,
      }));

    tableColumns.push({
      name: "",
      alias: "buttonActions",
    });

    this._tableColumns = tableColumns;
  }

  #createTableItems(schema: Array<EntrySearchResultSchema>) {
    this._tableItems = this.#entries.map((entry) => {
      const fields = entry.fields.map((f) => ({
        columnAlias: f.fieldId,
        value: this.#renderValue(f, schema),
      }));

      fields.push({
        columnAlias: "buttonActions",
        value: html`<uui-button
          .label=${this.localize.term("formEntries_entryDetails")}
          look="secondary"
          color="default"
          @click=${(e: Event) => this.#onViewDetailsClick(e, entry.unique)}
        ></uui-button>`,
      });

      return {
        id: entry.unique,
        icon: "icon-collection",
        data: fields,
      };
    });
  }

  #renderValue(field: FieldData, schema: Array<EntrySearchResultSchema>) {
    const schemaItem = schema.find((s) => s.id === field.fieldId);
    if (!schemaItem) {
      return html`${field.value}`;
    }

    const entryRenderHelper = new EntryRenderHelper(this, this.#fieldPrevalues);

    // Handle special cases of system fields, otherwise devolve to helper sharing rendering code between collection and modal.
    switch (schemaItem.view) {
      case "member": {
        if (!field.value) return null;

        const member = field.value as { name: string; email: string };
        return html`${member.name}`;
      }
      case "workflowSummary":
        return html`<span
          style="color: ${this.#getWorkflowSummaryStatusColor(
            field.value as string
          )}"
          >${field.value}</span
        >`;
      default: {
        const value = entryRenderHelper.getRenderValue(field, schemaItem.view);
        return html`${value}`;
      }
    }
  }


  #getWorkflowSummaryStatusColor(value: string) {
    return value.split("/")[0] === value.split("/")[1] ? "green" : "red";
  }

  #onViewDetailsClick(e: Event, unique: string) {
    e.stopImmediatePropagation();

    history.pushState(
      {},
      "",
      `${location.href}/modal/forms-entrydetails-modal/${unique}`
    );
  }

  #onSelect(event: UmbTableSelectedEvent) {
    event.stopPropagation();
    this.#updateSelection(event.target as UmbTableElement);
  }

  #onDeselect(event: UmbTableDeselectedEvent) {
    event.stopPropagation();
    this.#updateSelection(event.target as UmbTableElement);
  }

  #updateSelection(table: UmbTableElement) {
    const selection = table.selection;
    this.#collectionContext?.selection.setSelection(selection);
  }

  render() {
    return html`
      ${when(this._loading,
        () => html`<uui-loader-bar></uui-loader-bar>`)}
      <umb-table
        .config=${this._tableConfig}
        .columns=${this._tableColumns}
        .items=${this._tableItems}
        @selected="${this.#onSelect}"
        @deselected="${this.#onDeselect}"
      ></umb-table>`;
  }

  static styles = [
    UmbTextStyles,
    css`
      :host {
        display: flex;
        flex-direction: column;
      }
      umb-table {
        padding: 0;
      }
      .workflow-summary-success {
        color: green;
      }
      .workflow-summary-failure {
        color: red;
      }
    `,
  ];
}

export default FormsFormEntryTableCollectionViewElement;

declare global {
  interface HTMLElementTagNameMap {
    [elementName]: FormsFormEntryTableCollectionViewElement;
  }
}
